def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 2, -1):
                for b in range(1, a + 4):
                    z = ((ratio - a) ** 6) / (a * b * 1.1 + 0.5)
                    priority += z * np.sin(ratio * b / (a + 0.8))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.7
            for d in range(1, 5):
                if (i + d) % 2 == 0:
                    priority += np.tanh(ratio * d) * 0.5
                else:
                    priority -= np.sinh(ratio / d) * 0.4
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p) / (q + 0.7)
                    priority += np.tanh(term) * 1.4
            priority += np.log1p(ratio) * 11 - np.tanh(ratio - 5) * 2.5
            for s in range(3, 7):
                priority += (np.sin(ratio * s) ** 2) / (s + 0.3)
        elif 2 < ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.0) * np.sin(r * ratio * 0.9)
            priority = (s * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2.0
            for u in range(1, 5):
                priority += np.cos(u * ratio) * (ratio - 2) ** u / u
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 20):
                s += ((2 - ratio) ** n) / (n ** 2 + 1.0)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.sin(15 * ratio) * 3
            priority = s + penalty + np.exp(-2.0 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.7) * ((ratio - 1) ** m) / m
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
            for k in range(2, 6):
                if (i + k) % 4 == 0:
                    priority += np.cos(ratio * k * i) * 0.4
                else:
                    priority -= np.sin(ratio * k * i) * 0.4
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 18):
                s += ((0.4 - ratio) ** k) / (k * 3) * np.sin(k * ratio * 2.1)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 2.1) % 5 == 0:
                priority *= 3.0
            else:
                priority /= 3.0
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.8) * 3.5
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.25)
            for n in range(1, 4):
                priority += np.tanh(ratio * n * i) * 0.6
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.cos(t * item * 0.95)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.sin(item * u * 0.85)
            for v in range(1, 5):
                if (i + v * 2) % 3 == 0:
                    priority += np.cos(ratio * v * i) * 0.5
                else:
                    priority -= np.sin(ratio * v * i) * 0.5
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 0.8) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 0.8) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
